{
  "statusline": {
    "enabled": true,
    "terminal-bar": {
      "enabled": true,
      "position": "bottom",
      "format": "single-line",
      "refresh-rate": 100,
      "visual": true
    },
    "components": [
      {
        "type": "model",
        "label": "IA",
        "format": "🤖 {model-name}"
      },
      {
        "type": "token-bar",
        "label": "Tokens",
        "format": "[{progress-bar}] {used}/{limit} ({percentage}%)",
        "bar-width": 20,
        "colors": {
          "safe": "🟢",
          "warning": "🟡",
          "critical": "🔴"
        }
      },
      {
        "type": "cost-real",
        "label": "Gasto",
        "format": "💰 R$ {total-cost-brl}",
        "currency": "BRL",
        "exchange-rate": 5.0,
        "cost-per-model": {
          "haiku": 4.0,
          "sonnet": 15.0,
          "opus": 75.0
        }
      },
      {
        "type": "directory",
        "label": "Pasta",
        "format": "📁 {current-path}",
        "max-length": 25,
        "context-folder": "mariana"
      },
      {
        "type": "user",
        "label": "Usuário",
        "format": "👤 {username}"
      }
    ]
  },
  "token-limits": {
    "daily-limit": 200000,
    "session-limit": 50000,
    "real-time-tracking": true,
    "alerts": {
      "enabled": true,
      "warning-80": {
        "threshold": 0.80,
        "indicator": "🟡",
        "message": "80% do limite"
      },
      "warning-90": {
        "threshold": 0.90,
        "indicator": "🔴",
        "message": "90% do limite"
      },
      "warning-95": {
        "threshold": 0.95,
        "indicator": "🛑",
        "message": "95% do limite"
      }
    }
  },
  "terminal": {
    "visible": true,
    "position": "bottom",
    "height": "25%",
    "show-status-bar": true,
    "real-time-update": true
  },
  "currency": {
    "primary": "BRL",
    "display-format": "R$ {amount}",
    "exchange-rate": 5.0
  },
  "auto-actions": {
    "save-on-threshold": 0.90,
    "close-tabs-on-threshold": 0.95
  }
}
